class Solution:
    def minimumAbsDifference(self, arr):
        best = None
        for i in range(len(arr)):
            for j in range(len(arr)):
                if i != j:
                    d = abs(arr[i] - arr[j])
                    if best is None or d < best:
                        best = d
        pairs = []
        for i in range(len(arr)):
            for j in range(len(arr)):
                if arr[i] < arr[j] and arr[j] - arr[i] == best:
                    pairs.append([arr[i], arr[j]])
        pairs.sort()
        return pairs

