var minimumAbsDifference = function(arr) {
    arr = arr.slice().sort((a, b) => a - b);
    let best = Infinity;
    for (let i = 0; i + 1 < arr.length; i++) best = Math.min(best, arr[i + 1] - arr[i]);
    const res = [];
    for (let i = 0; i + 1 < arr.length; i++) if (arr[i + 1] - arr[i] === best) res.push([arr[i], arr[i + 1]]);
    return res;
};
